        "EstadoLlamadaBienvenida" character varying(20),
        "ObservacionesPlanManejo" character varying(2000),
        "NumeroTelefonoLlamadaBienvenida" character varying(20),
        "DiasEstancia" integer,
        "NumeroDiasAutorizado" character varying(50),
        "RequiereServiciosComplementarios" character varying(2),
        "PacienteGestante" character varying(2),
        "Nebulizaciones" character varying(2),
        "SistemasPresionNegativaVac" character varying(2),
        "NutricionParenteral" character varying(2),
        "NutricionEnteral" character varying(2),
        "PacienteAnticoagulado" character varying(2),
        "LaboratorioClinicoProcedimiento" character varying(2),
        "ClinicaHeridas" character varying(2),
        "CateterismoOSv" character varying(2),
        "CateterPicc" character varying(2),
        "NumeroCalibreSonda" integer,
        "FechaUltimoCambioSonda" date,
        "AuxiliarAsignadoCateterismo" character varying(120),
        "FechaProximoCambioSonda" date,
        "FechaUltimaCuracionPicc" date,
        "FechaAlta" date,
        "NombreQuienGestionaAlta" character varying(200),
        "AltaTardia" character varying(2),
        "FechaPrimerSeguimiento24Horas" date,
        "FechaSegundoSeguimiento48Horas" date,
        "FechaTercerSeguimiento72Horas" date,
        "ObservacionAltaTardia" character varying(2000),
        "NombreQuienRealizaSeguimientoAltaTardia" character varying(120),
        "PacienteRehospitalizado" character varying(2),
        "FechaRegistroReporteRehospitalizacion" date,
        "FechaRehospitalizacion" date,
        "MotivoRehospitalizacion" character varying(80),
        "AmpliacionMotivoRehospitalizacion" character varying(2000),
        "RemitidoPorRehospitalizacion" character varying(50),
        "IpsIntramuralRehospitalizacion" character varying(200),
        "FechaPrimerSeguimientoRehospitalizacion" date,
        "FechaSegundoSeguimientoRehospitalizacion" date,
        "FechaTercerSeguimientoRehospitalizacion" date,
        "FechaAltaHospitalizacion" date,
        "ObservacionRehospitalizacion" character varying(2000),
        "FechaNovedadDevolucionProductos" date,
        "MotivoNovedadDevolucionProductos" character varying(40),
        "NotificacionAuxiliarDevolucionProductos" character varying(2),
        "FechaMaximaDevolucionProductos" date,
        "EstadoDevolucionServicioFarmaceutico" character varying(20),
        "PresentaNovedadKardex" character varying(2),
        "PresentaNovedadRequisicion" character varying(2),
        "PresentaNovedadAutorizacion" character varying(2),
        "DescripcionNovedadDocumentosPaciente" character varying(2000),
        "FechaReporteNovedadDocumentos" date,
