DO $EF$
BEGIN
    IF NOT EXISTS(SELECT 1 FROM "__EFMigrationsHistory" WHERE "MigrationId" = '20260427170713_InitialPostgreSql') THEN
    PERFORM setval(
        pg_get_serial_sequence('"Permissions"', 'Id'),
        GREATEST(
            (SELECT MAX("Id") FROM "Permissions") + 1,
            nextval(pg_get_serial_sequence('"Permissions"', 'Id'))),
        false);
    PERFORM setval(
        pg_get_serial_sequence('"Roles"', 'Id'),
        GREATEST(
            (SELECT MAX("Id") FROM "Roles") + 1,
            nextval(pg_get_serial_sequence('"Roles"', 'Id'))),
        false);
    END IF;
END $EF$;

